mapper.select:
SELECT memoryno, memberno, dogno, source_chatno, memory_type, memory_text, importance, use_count, last_used, active_yn, rdate
FROM chat_memory
WHERE memoryno = #{memoryno}

mapper.update:
UPDATE chat_memory
SET memory_type = #{memory_type}, memory_text = #{memory_text}, importance = #{importance}, active_yn = #{active_yn}
WHERE memoryno = #{memoryno}

UPDATE chat_memory

SET use_count = use_count + 1

WHERE memoryno = #{memoryno}

UPDATE chat_memory

SET last_used = SYSDATE

WHERE memoryno = #{memoryno}

UPDATE chat_memory

SET active_yn = #{active_yn}

WHERE memoryno = #{memoryno}
